preQuery: SELECT noticeboards.id, noticeboards.name, noticeboards.lat, noticeboards.lng FROM noticeboards  
              INNER JOIN authorities ON authorities.id = ?  
              WHERE authorities.name IS NOT NULL AND active = 1 AND ST_CONTAINS(authorities.polygon, ST_SRID(POINT(noticeboards.lng, noticeboards.lat), ?));

preQuery: SELECT id, chatid FROM chat_messages WHERE 
userid IN (SELECT userid FROM spam_users WHERE collection = 'Spammer')
AND reviewrejected != 1;

preExec: INSERT INTO messages_edits (msgid, oldtext, newtext, oldsubject, newsubject, 
              oldtype, newtype, olditems, newitems, oldimages, newimages, oldlocation, newlocation, byuser, reviewrequired) 
              VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?);

preQuery: SELECT chat_messages.id, chat_messages.userid, lastmsgseen, lastmsgemailed FROM chat_messages 
LEFT JOIN chat_roster ON chat_roster.id = chat_messages.id AND chat_roster.userid = ? 
WHERE chat_messages.chatid = ? AND chat_messages.userid != ? AND seenbyall = 0 AND mailedtoall = 0 ORDER BY id DESC LIMIT 1;

preQuery: SELECT groupid FROM memberships
                INNER JOIN `groups` ON memberships.groupid = groups.id AND groups.type = ?
                WHERE userid = ?;

preQuery: SELECT giftaid.*, SUM(users_donations.GrossAmount) AS donations FROM giftaid 
                                                LEFT JOIN users_donations ON users_donations.userid = giftaid.userid
                                                WHERE reviewed IS NULL AND deleted IS NULL AND period != ? GROUP BY giftaid.userid ORDER BY timestamp DESC;

preQuery: SELECT users_emails.userid AS emailid, users_donations.id AS donationid FROM users_donations 
    INNER JOIN users_emails ON users_emails.email = users_donations.Payer 
         WHERE users_donations.userid IS NULL;
